I18N.register("pt", {
  tips: {
    "Look at Rows and Columns Separately": ["Observe linhas e colunas separadamente", "Em uma grade de números, verifique primeiro cada linha e depois cada coluna. Muitas vezes uma direção segue uma regra simples: conte de 2 a 2 ou de 3 a 3."],
    "Find the Rule Between Numbers": ["Encontre a regra entre os números", "Pergunte a si mesmo: o que devo adicionar, subtrair, multiplicar ou dividir para ir de um número a outro? Experimente cada operação até encontrar uma que funcione para cada etapa."],
    "Watch for Repeating Groups": ["Cuidado com grupos repetidos", "Às vezes, um grupo de formas ou símbolos se repete indefinidamente. Conte quantos elementos o grupo possui e depois veja onde você está no ciclo."],
    "Use Elimination": ["Usar eliminação", "Se não tiver certeza, tente cada resposta: coloque no padrão e veja se a regra ainda funciona. Elimine qualquer resposta que quebre o padrão."],
    "Find the Difference": ["Procure a diferença", "Subtraia cada número do anterior. Se a diferença for sempre a mesma, a regra é simples adição ou subtração."],
    "Try Multiplying or Dividing": ["Tente multiplicar ou dividir", "Divida cada número pelo número anterior. Se você obtiver o mesmo resultado todas as vezes, a string será multiplicada ou dividida pelo mesmo fator."],
    "Check for Two-Step Rules": ["Verifique as regras em duas etapas", "Às vezes, a regra combina duas operações (por exemplo, primeiro +2 e depois ×2). Escreva as etapas no rascunho e siga-as na ordem."],
    "Write It Down": ["Escreva no papel", "Escreva os números e as diferenças ou proporções abaixo deles. No papel você pode ver o padrão com mais facilidade do que apenas a olho nu."],
    "Read Every Word Carefully": ["Leia cada palavra com atenção", "Na lógica, os detalhes importam: palavras pequenas como «todos», «alguns», «nenhum», «certamente» mudam o significado. Leia a pergunta duas vezes antes de escolher."],
    "Draw a Picture or List": ["Desenhe ou faça uma lista", "Descreva as pessoas, dias ou relacionamentos no problema. Uma simples lista ou desenho mostra claramente quem é maior, quem vem primeiro, etc."],
    "Watch Out for Traps": ["Cuidado com as armadilhas", "De “todos os cães são animais” não se segue “todos os animais são cães”. Não inverta a regra por engano."],
    "Use 'If... Then...' Thinking": ["Pense \"se... então...\"", "Reformule as afirmações como «se A, então B». Siga a cadeia: se A for verdadeiro, o que deverá ser verdadeiro a seguir?"],
    "Picture It in Your Mind": ["Imagine isso em sua mente", "Para formas e cubos, tente “ver” a rotação ou dobra. Você pode fazer um esboço rápido no rascunho."],
    "Know the Basics of Common Shapes": ["Conhece o básico dos formulários comuns", "O cubo tem 6 faces, 12 arestas e 8 vértices. O prisma triangular tem 5 faces. Repita esses fatos e eles se tornarão automáticos."],
    "Count What You Cannot See": ["Contar e o que não se vê", "Em cubos colados, as faces ocultas onde elas se tocam não contam como faces visíveis. Subtraia as faces “coladas” do total."],
    "Use Nets to Understand Folding": ["Use o desdobramento para entender a dobra", "O desdobramento (o “quadrado” recortado que se dobra no cubo) mostra quais faces são vizinhas. Siga um rosto e veja em qual ele fica."],
    "Read the Problem Twice": ["Leia o problema duas vezes", "Muitos problemas de armadilhas são baseados na pressa. A segunda leitura capta frases como “todos menos…” ou “permanecem”."],
    "Look for Trick Words": ["Pesquise palavras-chave armadilhas", "Expressões como “todos menos”, “permanecem”, “no total”, “cada” alteram o cálculo. Sublinhe-os."],
    "Break It Into Steps": ["Divida em etapas", "Resolva por sua vez: primeiro o que você tem certeza, depois adicione ou subtraia de acordo com o problema. Não tente tudo de uma vez."],
    "Check Your Answer": ["Verifique a resposta", "Depois de calcular, volte à pergunta: A resposta faz sentido na história? Refaça o cálculo mais uma vez, se necessário."],
  },
  q: {
    "TPR811_1_01": ["O que vem a seguir na fila? 2, 4, 6, 8, __", "Conte de 2 a 2.", ["9", "10", "12", "11"], "A string aumenta 2 em cada etapa: 2, 4, 6, 8, 10."],
    "TPR811_1_02": ["O que vem a seguir? 5, 10, 15, 20, __", "Os números são múltiplos do mesmo número base.", ["22", "30", "25", "24"], "A string aumenta 5 em cada etapa: 5, 10, 15, 20, 25."],
    "TPR811_1_03": ["O que vem a seguir? 3, 6, 9, 12, __", "Pense em multiplicar por 3 (o tabuleiro 3).", ["14", "15", "16", "13"], "A string aumenta 3 em cada etapa: 3, 6, 9, 12, 15."],
    "TPR811_1_04": ["O que vem a seguir? 10, 20, 30, 40, __", "Conte de 10 a 10.", ["45", "55", "50", "60"], "A string aumenta em 10 a cada passo: 10, 20, 30, 40, 50."],
    "TPR811_1_05": ["O que vem a seguir? 4, 8, 12, 16, __", "Eles são múltiplos de 4.", ["18", "22", "24", "20"], "A string aumenta 4 em cada etapa: 4, 8, 12, 16, 20."],
    "TPR811_1_06": ["Qual é o número que falta? 1, 3, 5, __, 9", "São números ímpares.", ["6", "8", "7", "4"], "São números ímpares que aumentam 2: 1, 3, 5, 7, 9."],
    "TPR811_1_07": ["O que vem a seguir? 2, 5, 8, 11, __", "Quanto isso soma de cada vez?", ["12", "13", "15", "14"], "Cada número é 3 a mais que o anterior: 2, 5, 8, 11, 14."],
    "TPR811_1_08": ["Qual é o número que falta? 6, 12, __, 24, 30", "Conte de 6 a 6.", ["15", "18", "20", "16"], "A string aumenta de 6: 6, 12, 18, 24, 30."],
    "TPR811_1_09": ["O que vem a seguir na fila? ○, □, ○, □, ○, __", "As formas se alternam.", ["○", "△", "□", "◇"], "Círculo e quadrado se alternam. Depois do círculo vem o quadrado: ○, □, ○, □, ○, □."],
    "TPR811_1_10": ["O que vem a seguir? 7, 14, 21, 28, __", "Pense em multiplicar por 7 (o tabuleiro 7).", ["30", "32", "36", "35"], "A sequência aumenta 7 a cada passo: 7, 14, 21, 28, 35."],
    "TPR811_1_11": ["Qual é o número que falta? 10, __, 30, 40, 50", "Conte de 10 a 10.", ["15", "25", "20", "12"], "A string aumenta de 10: 10, 20, 30, 40, 50."],
    "TPR811_1_12": ["O que vem a seguir? 1, 4, 7, 10, __", "Quanto isso soma de cada vez?", ["12", "14", "11", "13"], "Cada número é 3 a mais que o anterior: 1, 4, 7, 10, 13."],
    "TPR811_1_13": ["O que vem a seguir na fila? A, B, A, B, A, __", "As letras se alternam.", ["Um", "c", "B", "d"], "Alternar A e B: A, B, A, B, A, B."],
    "TPR811_1_14": ["O que vem a seguir? 8, 16, 24, 32, __", "Eles são múltiplos de 8.", ["36", "38", "40", "42"], "A string aumenta de 8: 8, 16, 24, 32, 40."],
    "TPR811_1_15": ["Qual é o número que falta? 5, 10, __, 20, 25", "Conte de 5 a 5.", ["12", "14", "16", "15"], "A string aumenta de 5: 5, 10, 15, 20, 25."],
    "TPR811_1_16": ["O que vem a seguir? 9, 18, 27, 36, __", "Eles são múltiplos de 9.", ["45", "40", "42", "44"], "A string aumenta de 9: 9, 18, 27, 36, 45."],
    "TPR811_1_17": ["O que vem a seguir na fila? ★, ♥, ★, ♥, ★, __", "Dois símbolos se alternam.", ["★", "♥", "♦", "○"], "Estrela e coração alternam: ★, ♥, ★, ♥, ★, ♥."],
    "TPR811_1_18": ["Qual é o número que falta? 2, 4, __, 8, 10", "Conte de 2 a 2.", ["5", "7", "6", "3"], "A string aumenta de 2: 2, 4, 6, 8, 10."],
    "TPR811_1_19": ["O que vem a seguir? 11, 22, 33, 44, __", "Eles são múltiplos de 11.", ["50", "55", "54", "56"], "A string aumenta de 11: 11, 22, 33, 44, 55."],
    "TPR811_1_20": ["O que vem a seguir na fila? 1, 2, 1, 2, 1, __", "Os números sempre repetem o mesmo.", ["1", "3", "2", "0"], "Os números 1 e 2 se alternam: 1, 2, 1, 2, 1, 2."],
    "TPR811_2_01": ["Em uma grade, a linha 1 é: 2, 4, 6, 8. a linha 2 é: 3, 6, 9, 12. a linha 3 é: 4, 8, __, 16. Qual é o número que falta?", "Cada linha contém múltiplos do primeiro número dessa linha.", ["10", "11", "12", "14"], "A linha 3 contém múltiplos de 4: 4, 8, 12, 16."],
    "TPR811_2_02": ["O que vem a seguir? 1, 2, 4, 8, __", "Cada número é duplicado.", ["10", "12", "14", "16"], "Cada número é multiplicado por 2: 1, 2, 4, 8, 16."],
    "TPR811_2_03": ["O que vem a seguir? 3, 9, 27, __", "Cada número é multiplicado pelo mesmo fator.", ["36", "54", "81", "30"], "Cada número é multiplicado por 3: 3, 9, 27, 81."],
    "TPR811_2_04": ["O que vem a seguir na string? △, △, □, △, △, □, △, △, __", "Encontra o grupo de símbolos repetidos.", ["△", "□", "○", "★"], "O padrão se repete △, △, □ sempre igual. A posição 9 é □."],
    "TPR811_2_05": ["Grade: a linha 1 é 1, 2, 3. A linha 2 é 2, 4, 6. A linha 3 é 3, 6, __. Qual é o número que falta?", "Cada linha multiplica a primeira linha pelo número da linha.", ["7", "8", "9", "10"], "Linha 3 = linha superior × 3. Portanto, 3 × 3 = 9."],
    "TPR811_2_06": ["O que vem a seguir? 2, 6, 18, 54, __", "Multiplique pelo mesmo número todas as vezes.", ["108", "162", "72", "60"], "Cada número é multiplicado por 3: 2, 6, 18, 54, 162."],
    "TPR811_2_07": ["O que vem a seguir? 64, 32, 16, __", "Cada número é dividido pela metade.", ["12", "10", "4", "8"], "Cada número é divisível por 2: 64, 32, 16, 8."],
    "TPR811_2_08": ["Grade: A linha 1 é 1, 3, 5, 7. A linha 2 é 2, 6, 10, 14. A linha 3 é 3, 9, __, 21. Qual é o número que falta?", "Linha 2 = Linha 1 × 2. Quanto custa a Linha 3?", ["12", "15", "13", "17"], "Linha 3 = Linha 1 × 3. Portanto, 5 × 3 = 15."],
    "TPR811_2_09": ["O que vem a seguir? 4, 8, 16, 32, __", "Cada número é duplicado.", ["48", "40", "64", "36"], "Cada número é multiplicado por 2: 4, 8, 16, 32, 64."],
    "TPR811_2_10": ["O que vem a seguir na fila? ★, ♦, ♦, ★, ♦, ♦, ★, ♦, ♦, ★, __", "Encontre o grupo repetidor.", ["★", "♦", "○", "□"], "O padrão se repete ★, ♦, ♦. A posição 11 é ♦."],
    "TPR811_2_11": ["O que vem a seguir? 5, 25, 125, __", "Multiplique pelo mesmo número todas as vezes.", ["150", "500", "250", "625"], "Cada número é multiplicado por 5: 5, 25, 125, 625."],
    "TPR811_2_12": ["Grade: a linha 1 é 2, 4, 6. A linha 2 é 3, 6, 9. A linha 3 é 5, 10, __. Qual é o número que falta?", "Cada linha contém múltiplos do primeiro número dessa linha.", ["12", "14", "15", "20"], "A linha 3 contém múltiplos de 5: 5, 10, 15."],
    "TPR811_2_13": ["O que vem a seguir? 1, 4, 9, 16, __", "São quadrados perfeitos: 1², 2², 3², 4²...", ["20", "25", "24", "36"], "São números quadrados: 1, 4, 9, 16, 25 (que tem 1², 2², 3², 4², 5²)."],
    "TPR811_2_14": ["O que vem a seguir na fila? A, A, B, A, A, B, A, A, B, __", "Encontre o grupo repetido de 3.", ["Um", "B", "c", "d"], "O padrão repete A, A, B. A posição 10 inicia um novo grupo começando com A."],
    "TPR811_2_15": ["O que vem a seguir? 1, 1, 2, 3, 5, 8, __", "Adicione os dois números anteriores.", ["10", "11", "12", "13"], "Cada número é a soma dos dois anteriores: 5 + 8 = 13. Esta é a sequência de Fibonacci."],
    "TPR811_2_16": ["Grade: A linha 1 é 1, 2, 3, 4. A linha 2 é 2, 4, 6, 8. A linha 3 é 4, 8, __, 16. Qual é o número que falta?", "Linha 3 = Linha 1 × 4.", ["10", "12", "14", "9"], "Linha 3 = Linha 1 × 4. Portanto, 3 × 4 = 12."],
    "TPR811_2_17": ["O que vem a seguir? 10, 100, 1000, __", "Multiplique por 10 em cada etapa.", ["1100", "2000", "10.000", "5.000"], "Cada número é multiplicado por 10: 10, 100, 1000, 10000."],
    "TPR811_2_18": ["O que vem a seguir? 1, 3, 6, 10, __", "Veja as diferenças: +2, +3, +4…", ["13", "14", "15", "12"], "A diferença aumenta em 1 a cada passo: +2, +3, +4, +5. Portanto, 10 + 5 = 15. Estes são números triangulares."],
    "TPR811_2_19": ["O que vem a seguir? 1000, 500, 250, 125, __", "Cada número é dividido pela metade.", ["62,5", "100", "75", "60"], "Cada número é divisível por 2: 1000, 500, 250, 125, 62,5."],
    "TPR811_2_20": ["O que vem a seguir? 1, 8, 27, 64, __", "Estes são números de cubo: 1³, 2³, 3³, 4³...", ["100", "81", "125", "216"], "Estes são números de cubo: 1³=1, 2³=8, 3³=27, 4³=64, 5³=125."],
    "TPR811_3_01": ["O que vem a seguir? 1, 3, 7, 15, __", "Tente multiplicar por 2 e depois adicionar 1.", ["29", "30", "31", "23"], "Regra: ×2 depois +1. 1→3, 3→7, 7→15, 15→31."],
    "TPR811_3_02": ["O que vem a seguir? 2, 5, 11, 23, __", "Tente ×2 e depois +1.", ["35", "46", "47", "45"], "Regra: ×2 depois +1. 2→5, 5→11, 11→23, 23→47."],
    "TPR811_3_03": ["O que vem a seguir na fila? ○, ○, □, △, ○, ○, □, △, ○, ○, __", "Encontre o grupo de 4 símbolos repetidos.", ["○", "△", "□", "★"], "O padrão se repete: ○, ○, □, △. A posição 11 é □."],
    "TPR811_3_04": ["O que vem a seguir? 1, 4, 13, 40, __", "Tente ×3 e depois +1.", ["80", "121", "120", "81"], "Regra: ×3 e depois +1. 1→4, 4→13, 13→40, 40→121."],
    "TPR811_3_05": ["Grade: a linha 1 é 1, 4, 7. A linha 2 é 3, 10, 17. A linha 3 é 5, 16, __. Cada linha segue a mesma regra de adição e a coluna 1 possui os valores 1, 3, 5. Qual é o número que falta?", "A linha 1 reúne 3 em cada etapa. A linha 2 reúne 7 em cada etapa. A linha 3 adiciona... observe os dois primeiros números.", ["27", "25", "21", "23"], "Linha 3: 5, 16, 27. A diferença é 11 em cada etapa (5+11=16, 16+11=27)."],
    "TPR811_3_06": ["O que vem a seguir? 2, 6, 14, 30, __", "Tente ×2 e depois +2.", ["58", "60", "62", "56"], "Regra: ×2 depois +2. 2→6, 6→14, 14→30, 30→62."],
    "TPR811_3_07": ["O que vem a seguir? 3, 7, 15, 31, __", "Tente ×2 e depois +1.", ["47", "62", "63", "60"], "Regra: ×2 depois +1. 3→7, 7→15, 15→31, 31→63."],
    "TPR811_3_08": ["O que vem a seguir? 1, 2, 5, 10, 17, __", "Veja as diferenças entre os números: 1, 3, 5, 7...", ["24", "25", "26", "22"], "As diferenças são números ímpares: +1, +3, +5, +7, +9. Então 17 + 9 = 26."],
    "TPR811_3_09": ["Grade: a linha 1 é 1, 4, 7. A linha 2 é 2, 8, 14. A linha 3 é 3, 12, __. Qual é o número que falta?", "Linha 2 = Linha 1 × 2. Linha 3 = Linha 1 ×?", ["18", "21", "15", "24"], "Linha 3 = Linha 1 × 3. Portanto, 7 × 3 = 21."],
    "TPR811_3_10": ["O que vem a seguir? 0, 1, 3, 7, 15, __", "Tente ×2 e depois +1.", ["31", "30", "23", "29"], "Regra: ×2 depois +1. 0→1, 1→3, 3→7, 7→15, 15→31."],
    "TPR811_3_11": ["O que vem a seguir? 2, 3, 5, 9, 17, __", "Veja as diferenças: elas duplicam a cada passo.", ["25", "33", "31", "34"], "As diferenças são duplicadas: +1, +2, +4, +8, +16. Então 17 + 16 = 33."],
    "TPR811_3_12": ["O que vem a seguir? 1, 2, 6, 24, __", "1×2=2, 2×3=6, 6×4=24, 24×?...", ["48", "120", "96", "30"], "Multiplique por números crescentes: ×2, ×3, ×4, ×5. Portanto, 24 × 5 = 120."],
    "TPR811_3_13": ["Grade: a linha 1 é 2, 3, 4. A linha 2 é 5, 7, 9. A linha 3 é 11, 15, __. A regra entre linhas é ×2 e depois +1. Qual é o número que falta?", "Aplique a regra a cada número na linha 2.", ["17", "18", "19", "21"], "9 × 2 + 1 = 19."],
    "TPR811_3_14": ["O que vem a seguir? 100, 98, 94, 86, 70, __", "Veja quanto é subtraído: 2, 4, 8, 16...", ["54", "38", "50", "42"], "Scadeions duplos: −2, −4, −8, −16, −32. Então 70 − 32 = 38."],
    "TPR811_3_15": ["O que vem a seguir? 1, 4, 10, 22, __", "Tente ×2 e depois +2.", ["44", "46", "34", "40"], "Regra: ×2 depois +2. 1→4, 4→10, 10→22, 22→46."],
    "TPR811_3_16": ["O que vem a seguir? 5, 11, 23, 47, __", "Tente ×2 e depois +1.", ["94", "95", "93", "96"], "Regra: ×2 depois +1. 5→11, 11→23, 23→47, 47→95."],
    "TPR811_3_17": ["O que vem a seguir? 1, 2, 4, 7, 11, 16, __", "A diferença aumenta em 1 a cada passo: +1, +2, +3, +4, +5...", ["21", "22", "20", "23"], "Diferenças: +1, +2, +3, +4, +5, +6. Então 16 + 6 = 22."],
    "TPR811_3_18": ["Colunas da grade: a coluna 1 é 1, 2, 4. a coluna 2 é 1, 3, 9. a coluna 3 é 1, 4, __. Qual é o número que falta?", "a coluna 1 é potência de 2. a coluna 2 é potência de 3. a coluna 3 é potência de ?", ["8", "12", "16", "20"], "a coluna 3 é potência de 4: 4⁰=1, 4¹=4, 4²=16."],
    "TPR811_3_19": ["O que vem a seguir? 2, 5, 14, 41, __", "Tente ×3 e depois −1.", ["82", "122", "123", "124"], "Regra: ×3 então −1. 2→5, 5→14, 14→41, 41→122."],
    "TPR811_3_20": ["O que vem a seguir? 1, 3, 9, 27, 81, __", "Cada número é multiplicado por 3.", ["162", "243", "108", "100"], "Cada número é ×3: 1, 3, 9, 27, 81, 243."],
    "TNR811_1_01": ["Quanto é 3 × 4?", "Pense em 3 grupos de 4.", ["7", "10", "12", "14"], "3 × 4 = 12."],
    "TNR811_1_02": ["Quanto é 5 × 6?", "Pense em 5 grupos de 6.", ["25", "30", "35", "36"], "5 × 6 = 30."],
    "TNR811_1_03": ["O que vem a seguir? 5, 10, 15, 20, __", "Conte de 5 a 5.", ["24", "25", "30", "22"], "Contando de 5 em 5: 5, 10, 15, 20, 25."],
    "TNR811_1_04": ["Qual é o dobro de 8?", "Duplo significa ×2.", ["14", "16", "18", "10"], "Duplo 8 = 8 × 2 = 16."],
    "TNR811_1_05": ["Quanto é 4 × 7?", "Pense em 4 grupos de 7.", ["24", "21", "28", "32"], "4 × 7 = 28."],
    "TNR811_1_06": ["O que vem a seguir? 3, 6, 9, 12, __", "Conte de 3 a 3.", ["13", "14", "15", "16"], "Contando de 3 em 3: 3, 6, 9, 12, 15."],
    "TNR811_1_07": ["Qual é o dobro de 15?", "Duplo significa multiplicar por 2.", ["25", "28", "30", "35"], "Duplo 15 = 15 × 2 = 30."],
    "TNR811_1_08": ["Quanto é 5 × 8?", "Pense em 5 grupos de 8.", ["35", "45", "40", "48"], "5 × 8 = 40."],
    "TNR811_1_09": ["Número de 4: 4, 8, 12, __, 20. Quanto falta?", "Quanto é 12 + 4?", ["14", "16", "15", "18"], "Contando de 4 em 4: 4, 8, 12, 16, 20."],
    "TNR811_1_10": ["Quanto é 3 × 9?", "Pense em 3 grupos de 9.", ["24", "27", "21", "29"], "3 × 9 = 27."],
    "TNR811_1_11": ["Qual é o dobro de 25?", "Duplo significa ×2.", ["45", "50", "55", "40"], "Duplo 25 = 25 × 2 = 50."],
    "TNR811_1_12": ["Quanto é 4 × 8?", "Pense em 4 grupos de 8.", ["28", "30", "32", "36"], "4 × 8 = 32."],
    "TNR811_1_13": ["Número de 6: 6, 12, 18, __, 30. Quanto falta?", "Quanto é 18 + 6?", ["22", "26", "24", "20"], "Contando de 6 em 6: 6, 12, 18, 24, 30."],
    "TNR811_1_14": ["Quanto é 5 × 9?", "Pense em 5 grupos de 9.", ["40", "50", "45", "54"], "5 × 9 = 45."],
    "TNR811_1_15": ["Qual é o dobro de 12?", "Duplo significa ×2.", ["22", "24", "20", "26"], "Duplo 12 = 12 × 2 = 24."],
    "TNR811_1_16": ["Quanto é 3 × 7?", "Pense em 3 grupos de 7.", ["18", "24", "21", "28"], "3 × 7 = 21."],
    "TNR811_1_17": ["Número de 3: 3, 6, 9, 12, 15, __. O que vem a seguir?", "Colete 3 em cada etapa.", ["16", "17", "18", "19"], "Contando de 3 em 3: 3, 6, 9, 12, 15, 18."],
    "TNR811_1_18": ["Quanto é 4 × 9?", "Pense em 4 grupos de 9.", ["32", "36", "40", "27"], "4 × 9 = 36."],
    "TNR811_1_19": ["Qual é o dobro de 35?", "Duplo significa ×2.", ["60", "65", "70", "75"], "Duplo 35 = 35 × 2 = 70."],
    "TNR811_1_20": ["Quanto é 5 × 7?", "Pense em 5 grupos de 7.", ["30", "35", "40", "42"], "5 × 7 = 35."],
    "TNR811_2_01": ["Quanto é metade de 48?", "Metade significa ÷2.", ["20", "22", "24", "28"], "Metade de 48 = 48 ÷ 2 = 24."],
    "TNR811_2_02": ["Qual é o triplo de 9?", "Triplo significa ×3.", ["18", "27", "24", "21"], "Triplo 9 = 9 × 3 = 27."],
    "TNR811_2_03": ["Sequência: 2, 4, 3, 6, 5, 10, 9, __. A regra alterna: dobre e depois subtraia 1. O que vem a seguir?", "9 vem depois de uma etapa de subtração. Qual é a próxima operação?", ["10", "18", "8", "12"], "O padrão alterna entre ×2 e −1. Depois do 9 dobramos: 9 × 2 = 18."],
    "TNR811_2_04": ["Quanto é metade de 64?", "Metade significa ÷2.", ["30", "34", "32", "36"], "Metade de 64 = 64 ÷ 2 = 32."],
    "TNR811_2_05": ["Qual é o triplo de 12?", "Triplo significa ×3.", ["24", "30", "36", "48"], "Triplo 12 = 12 × 3 = 36."],
    "TNR811_2_06": ["Sequência: 1, 3, 2, 6, 5, 15, 14, __. A regra alterna: ×3, depois -1. O que vem a seguir?", "14 vem depois de subtrair 1. Qual operação vem a seguir?", ["13", "28", "42", "15"], "Alternância: ×3 e −1. Depois de 14 multiplicamos: 14 × 3 = 42."],
    "TNR811_2_07": ["Quanto é metade de 100?", "Metade significa ÷2.", ["40", "50", "55", "45"], "Metade de 100 = 100 ÷ 2 = 50."],
    "TNR811_2_08": ["Qual é o triplo de 15?", "Triplo significa ×3.", ["30", "40", "45", "60"], "Triplo 15 = 15 × 3 = 45."],
    "TNR811_2_09": ["O que vem a seguir? 80, 40, 20, __", "Cada número é dividido pela metade.", ["15", "10", "5", "12"], "Cada número é divisível por 2: 80, 40, 20, 10."],
    "TNR811_2_10": ["Quanto é metade de 36?", "Metade significa ÷2.", ["16", "18", "20", "14"], "Metade de 36 = 36 ÷ 2 = 18."],
    "TNR811_2_11": ["Qual é o triplo de 20?", "Triplo significa ×3.", ["40", "50", "60", "80"], "Triplo 20 = 20 × 3 = 60."],
    "TNR811_2_12": ["Sequência: 1, 2, 4, 5, 10, 11, 22, __. A regra alterna: +1 e depois ×2. O que vem a seguir?", "22 vem depois de dobrar. Qual é a próxima operação?", ["23", "24", "44", "32"], "Alternação: +1 e ×2. Depois de 22 adicionamos 1: 22 + 1 = 23."],
    "TNR811_2_13": ["Quanto é metade de 56?", "Metade significa ÷2.", ["24", "26", "28", "30"], "Metade de 56 = 56 ÷ 2 = 28."],
    "TNR811_2_14": ["Qual é o triplo de 8?", "Triplo significa ×3.", ["16", "20", "24", "28"], "Triplo 8 = 8 × 3 = 24."],
    "TNR811_2_15": ["O que vem a seguir? 96, 48, 24, 12, __", "Cada número é dividido pela metade.", ["8", "6", "10", "4"], "Todo número é divisível por 2: 96, 48, 24, 12, 6."],
    "TNR811_2_16": ["Quanto é metade de 72?", "Metade significa ÷2.", ["32", "34", "36", "38"], "Metade de 72 = 72 ÷ 2 = 36."],
    "TNR811_2_17": ["Qual é o triplo de 25?", "Triplo significa ×3.", ["50", "65", "75", "100"], "Triplo 25 = 25 × 3 = 75."],
    "TNR811_2_18": ["Sequência: 5, 15, 10, 30, 25, 75, 70, __. A regra alterna: ×3, depois −5. O que vem a seguir?", "70 vem depois de subtrair 5. Qual é a próxima operação?", ["65", "140", "210", "105"], "Alternância: ×3 e −5. Depois de 70 multiplicamos: 70 × 3 = 210."],
    "TNR811_2_19": ["Quanto é metade de 84?", "Metade significa ÷2.", ["38", "40", "42", "44"], "Metade de 84 = 84 ÷ 2 = 42."],
    "TNR811_2_20": ["Qual é o triplo de 30?", "Triplo significa ×3.", ["60", "90", "100", "120"], "Triplo 30 = 30 × 3 = 90."],
    "TNR811_3_01": ["O que vem a seguir? 1, 3, 7, 15, 31, __", "Tente ×2 e depois +1.", ["47", "62", "63", "60"], "Regra: ×2 depois +1. 1→3, 3→7, 7→15, 15→31, 31→63."],
    "TNR811_3_02": ["O que vem a seguir? 2, 6, 18, 54, __", "Cada número é ×3.", ["108", "162", "72", "60"], "Cada número é multiplicado por 3: 2, 6, 18, 54, 162."],
    "TNR811_3_03": ["O que vem a seguir? 100, 97, 91, 82, 70, __", "Veja as diferenças: −3, −6, −9, −12...", ["58", "55", "52", "60"], "As diferenças aumentam em 3: −3, −6, −9, −12, −15. Então 70 − 15 = 55."],
    "TNR811_3_04": ["O que vem a seguir? 3, 4, 6, 10, 18, __", "Veja as diferenças: 1, 2, 4, 8... elas dobram.", ["26", "34", "28", "36"], "As diferenças são duplicadas: +1, +2, +4, +8, +16. Então 18 + 16 = 34."],
    "TNR811_3_05": ["O que vem a seguir? 2, 5, 11, 23, 47, __", "Tente ×2 e depois +1.", ["94", "95", "93", "96"], "Regra: ×2 depois +1. 2→5, 5→11, 11→23, 23→47, 47→95."],
    "TNR811_3_06": ["O que vem a seguir? 256, 128, 64, 32, __", "Cada número é dividido pela metade.", ["24", "16", "8", "20"], "Cada número é divisível por 2: 256, 128, 64, 32, 16."],
    "TNR811_3_07": ["O que vem a seguir? 1, 4, 13, 40, __", "Tente ×3 e depois +1.", ["80", "120", "121", "81"], "Regra: ×3 e depois +1. 1→4, 4→13, 13→40, 40→121."],
    "TNR811_3_08": ["O que vem a seguir? 50, 46, 40, 32, 22, __", "As diferenças aumentaram: −4, −6, −8, −10...", ["10", "12", "14", "8"], "As diferenças aumentam em 2: −4, −6, −8, −10, −12. Então 22 − 12 = 10."],
    "TNR811_3_09": ["O que vem a seguir? 3, 9, 27, 81, __", "Cada número é ×3.", ["162", "243", "108", "100"], "Cada número é multiplicado por 3: 3, 9, 27, 81, 243."],
    "TNR811_3_10": ["O que vem a seguir? 2, 3, 5, 9, 17, __", "As diferenças são duplicadas: +1, +2, +4, +8...", ["25", "33", "34", "31"], "As diferenças são duplicadas: +1, +2, +4, +8, +16. Então 17 + 16 = 33."],
    "TNR811_3_11": ["O que vem a seguir? 1, 5, 13, 29, __", "Tente ×2 e depois +3.", ["57", "58", "61", "45"], "Regra: ×2 depois +3. 1→5, 5→13, 13→29, 29→61."],
    "TNR811_3_12": ["O que vem a seguir? 200, 195, 185, 170, 150, __", "As diferenças aumentaram: −5, −10, −15, −20...", ["130", "125", "120", "135"], "As diferenças aumentam em 5: −5, −10, −15, −20, −25. Então 150 − 25 = 125."],
    "TNR811_3_13": ["O que vem a seguir? 4, 16, 64, 256, __", "Cada número é ×4.", ["512", "1024", "768", "640"], "Cada número é multiplicado por 4: 4, 16, 64, 256, 1024."],
    "TNR811_3_14": ["O que vem a seguir? 1, 2, 6, 24, 120, __", "Multiplique por 2, depois por 3, depois por 4, depois por 5...", ["240", "600", "720", "360"], "×2, ×3, ×4, ×5, ×6. Portanto, 120 × 6 = 720. Eles são chamados de fatoriais."],
    "TNR811_3_15": ["O que vem a seguir? 5, 8, 14, 26, 50, __", "As diferenças são duplicadas: +3, +6, +12, +24...", ["74", "98", "76", "100"], "As diferenças são duplicadas: +3, +6, +12, +24, +48. Então 50 + 48 = 98."],
    "TNR811_3_16": ["O que vem a seguir? 3, 10, 31, 94, __", "Tente ×3 e depois +1.", ["188", "282", "283", "281"], "Regra: ×3 e depois +1. 3→10, 10→31, 31→94, 94→283."],
    "TNR811_3_17": ["O que vem a seguir? 80, 77, 71, 62, 50, __", "As diferenças aumentaram: −3, −6, −9, −12...", ["35", "38", "40", "42"], "As diferenças aumentam em 3: −3, −6, −9, −12, −15. Então 50 − 15 = 35."],
    "TNR811_3_18": ["O que vem a seguir? 1, 2, 4, 8, 16, 32, __", "Cada número é duplicado.", ["48", "60", "64", "36"], "Cada número é ×2: 1, 2, 4, 8, 16, 32, 64."],
    "TNR811_3_19": ["O que vem a seguir? 2, 7, 22, 67, __", "Tente ×3 e depois +1.", ["134", "200", "201", "202"], "Regra: ×3 e depois +1. 2→7, 7→22, 22→67, 67→202."],
    "TNR811_3_20": ["O que vem a seguir? 1000, 990, 970, 940, 900, __", "As diferenças aumentaram: −10, −20, −30, −40...", ["860", "850", "840", "870"], "As diferenças aumentam em 10: −10, −20, −30, −40, −50. Então 900 − 50 = 850."],
    "TLR811_1_01": ["Todos os cães são animais. Spot é um cachorro. O que é ponto?", "Se Spot é um cachorro e todos os cachorros são animais…", ["Uma planta", "Um animal", "Um pássaro", "Um peixe"], "Todos os cães são animais. Spot é um cachorro. Então Spot é um animal."],
    "TLR811_1_02": ["Todas as maçãs são frutas. Todas as frutas são alimentos. Segue-se daí que todas as maçãs são comida?", "A cadeia é a seguinte: maçãs → frutas → alimentos.", ["Sim", "Não", "Apenas alguns", "Não podemos saber"], "Maçãs são frutas e frutas são alimentos. Então todas as maçãs são comida."],
    "TLR811_1_03": ["Tom é mais alto que Sam. Sam é mais alto que Ben. Quem é o mais alto?", "Coloque-os em ordem de altura.", ["Sam", "Bem", "Tom", "Eu sou o mesmo"], "Tom > Sam > Ben. Tom é o mais alto."],
    "TLR811_1_04": ["Todos os gatos têm cauda. Bigodes é um gato. Bigodes tem cauda?", "Se todos os gatos têm rabo e Bigodes é um gato…", ["Sim", "Não", "Talvez", "Só às vezes"], "Todos os gatos têm cauda. Bigodes é um gato. Então o Bigode tem rabo."],
    "TLR811_1_05": ["Ana é mais velha que Ben. Ben é mais velho que Cara. Quem é o mais novo?", "Ordene-os do mais velho para o mais novo.", ["Ana", "Bem", "Cara", "Eles têm a mesma idade"], "Ana > Ben > Cara com a idade. Cara é a mais nova."],
    "TLR811_1_06": ["Todos os pássaros têm penas. Uma andorinha é um pássaro. A andorinha tem penas?", "Se todos os pássaros tivessem penas...", ["Não", "Sim", "Só no inverno", "Talvez"], "Todos os pássaros têm penas. A andorinha é um pássaro. Então tem penas."],
    "TLR811_1_07": ["O vermelho é maior que o azul. Azul é maior que Verde. Qual é o menor?", "Classifique-os por tamanho.", ["Vermelho", "Azul", "Verde", "Eles são iguais"], "Vermelho > Azul > Verde. Verde é o menor."],
    "TLR811_1_08": ["Todos os peixes vivem na água. Um peixinho dourado é um peixe. Onde mora um peixinho dourado?", "Se todos os peixes vivessem na água…", ["Em terra seca", "Nas árvores", "Na água", "no céu"], "Todos os peixes vivem na água. Peixinhos dourados são peixes. Então ele vive na água."],
    "TLR811_1_09": ["O livro A tem mais páginas que o livro B. O livro B tem mais páginas que o livro C. Qual tem menos páginas?", "Classifique os livros por número de páginas.", ["Livro A", "Livro B", "Livro C", "Eles são iguais"], "A > B > C para páginas. O livro C tem o menor número de páginas."],
    "TLR811_1_10": ["Todos os quadrados têm 4 lados. Esta forma é um quadrado. Quantos lados ele tem?", "Se for quadrado…", ["3", "4", "5", "6"], "Todos os quadrados têm 4 lados. This shape is square. Então tem 4 lados."],
    "TLR811_1_11": ["Pizza é mais barata que bife. O bife é mais barato que a lagosta. Qual é o mais barato?", "Classifique-os por preço.", ["Bife", "A lagosta", "Pizza", "Custa o mesmo"], "Pizza <Bife <Lagosta a preço. Pizza é a mais barata."],
    "TLR811_1_12": ["Todas as rosas são flores. Todas as flores são plantas. A rosa é uma planta?", "A cadeia segue: rosas → flores → plantas.", ["Sim", "Não", "Talvez", "Apenas rosas vermelhas"], "Rosas são flores e flores são plantas. Então a rosa é uma planta."],
    "TLR811_1_13": ["A equipe A marcou mais que a equipe B. A equipe B marcou mais que a equipe C. Quem marcou mais?", "Classifique as equipes por pontuação.", ["Equipe C", "Equipe B", "Equipe A", "Igualdade"], "A > B > C na pontuação. O time A marcou mais."],
    "TLR811_1_14": ["Todas as moedas são redondas. Um centavo é uma moeda. Qual é o formato de um centavo?", "Se todas as moedas fossem redondas…", ["Quadrado", "Triângulo", "Rodada", "Oval"], "Todas as moedas são redondas. O centavo é moeda. Então é redondo."],
    "TLR811_1_15": ["Mia corre mais rápido que Lily. Lily corre mais rápido que Zoe. Quem é o mais lento?", "Classifique-os por velocidade.", ["Mia", "Lírio", "Zoé", "Eu sou o mesmo"], "Mia > Lily > Zoe em alta velocidade. Zoe é a mais lenta."],
    "TLR811_1_16": ["Todos os triângulos têm 3 lados. Esta forma tem 3 lados. Can it be a triangle?", "Os triângulos têm 3 lados. Isso significa necessariamente que a forma é um triângulo?", ["Sim, pode ser", "Não, nunca", "Só se for grande", "Só se for vermelho"], "Todos os triângulos têm 3 lados, e esta forma tem 3 lados, portanto pode ser um triângulo."],
    "TLR811_1_17": ["Um elefante é mais pesado que um cavalo. Um cavalo é mais pesado que um cachorro. Qual é o mais fácil?", "Classifique-os por peso.", ["O elefante", "O cavalo", "O cachorro", "eu canto o mesmo"], "Elefante > Cavalo > Cão por peso. O cachorro é o mais fácil."],
    "TLR811_1_18": ["Todos os lápis podem escrever. Isto é um lápis. Ele pode escrever?", "Se todos os lápis pudessem escrever…", ["Sim", "Não", "Só às vezes", "Nós não sabemos"], "Todos os lápis podem escrever. Isso é lápis. Então ele pode escrever."],
    "TLR811_1_19": ["A caixa A é mais larga que a caixa B. A caixa B é mais larga que a caixa C. Qual é mais larga?", "Classifique as caixas por largura.", ["Caixa C", "Caixa B", "Caixa A", "Eu sou o mesmo"], "A > B > C em largura. A caixa A é a mais larga."],
    "TLR811_1_20": ["Todo sorvete está frio. Isso é sorvete. está frio", "Se todo o sorvete estiver frio…", ["Não", "Talvez", "Sim", "Só no inverno"], "Todo sorvete está frio. Isso é sorvete. Então está frio."],
    "TLR811_2_01": ["Toată ciocolata é doce. Este doce é doce. O chocolate é SEGURO?", "Só porque todo chocolate é doce, isso significa que tudo que é doce é chocolate?", ["Sim, claro", "Não, não necessariamente", "Só chocolate amargo", "Sempre"], "Todo chocolate é doce, mas outras coisas também podem ser doces. Não é necessariamente chocolate."],
    "TLR811_2_02": ["Anna é mais alta que Ben. Ben é mais alto que Cara. Cara é mais alta que Dan. Quem é o segundo mais alto?", "Coloque todos os quatro em ordem de altura.", ["Ana", "Bem", "Cara", "Dan"], "Anna > Ben > Cara > Dan. Ben é o segundo mais alto."],
    "TLR811_2_03": ["Todos os carros têm rodas. Este veículo tem rodas. Um carro é SEGURO?", "Só os carros têm rodas?", ["Sim", "Não, não necessariamente", "Só se for vermelho", "Sempre"], "Muitos veículos possuem rodas (bicicletas, ônibus, caminhões). Não é necessariamente um carro."],
    "TLR811_2_04": ["O vermelho é maior que o azul. Azul é maior que Verde. Verde é maior que Amarelo. Qual é o terceiro maior?", "Classifique todos os quatro por tamanho.", ["Vermelho", "Azul", "Verde", "Amarelo"], "Vermelho > Azul > Verde > Amarelo. Verde é o terceiro maior."],
    "TLR811_2_05": ["Todos os quadrados são retângulos. Esta forma é retângulo. É CERTO quadrado?", "Todos os quadrados são retângulos, mas todos os retângulos são quadrados?", ["Sim", "Não, não necessariamente", "Só se for pequeno", "Sempre"], "Todos os quadrados são retângulos, mas nem todos os retângulos são quadrados. Pode não ser quadrado."],
    "TLR811_2_06": ["Kim obteve 90 pontos. Lee 85. Min 95. Pat 80. Quem ficou em segundo?", "Classifique da pontuação mais alta para a mais baixa.", ["Kim", "Lee", "Mínimo", "Cama"], "Min (95) > Kim (90) > Lee (85) > Pat (80). Kim ficou em segundo lugar."],
    "TLR811_2_07": ["Todos os cães estão latindo. Um animal late. É cachorro SEGURO?", "Só os cães latem?", ["Sim, claro", "Não, não necessariamente", "Só cachorros grandes latem", "Sempre"], "Outros animais também podem latir (por exemplo, focas). Não é necessariamente um cachorro."],
    "TLR811_2_08": ["O livro A tem 200 páginas. B é 150. C é 300. D é 250. Qual é o terceiro mais longo?", "Classifique da maioria das páginas para a menor.", ["Livro A", "Livro B", "Livro C", "Livro D"], "C (300) > D (250) > A (200) > B (150). O Livro A é o terceiro mais longo."],
    "TLR811_2_09": ["Todos os números pares são exatamente divisíveis por 2. O número 15 não é exatamente divisível por 2. O que podemos dizer sobre 15?", "Se não for divisível por 2, pode ser par?", ["É mesmo", "Não é cabelo", "Não podemos saber", "Pode ser até"], "Todos os números pares são divisíveis por 2. 15 não é divisível por 2. Portanto, 15 não é par."],
    "TLR811_2_10": ["Amy, Ben, Cat e Dan correm. Amy vence Ben. Cat supera Amy. Dan vence Cat. Quem está ganhando?", "Se Dan vencer Cat e Cat vencer Amy…", ["Amém", "Bem", "Gato", "Dan"], "Dan > Gato > Amy > Ben. Dan vence."],
    "TLR811_2_11": ["Todas as bicicletas têm 2 rodas. Este veículo tem 2 rodas. A bicicleta é SEGURA?", "Só as bicicletas têm 2 rodas?", ["Sim", "Não, não necessariamente", "Apenas bicicletas de montanha", "Sempre"], "E as scooters, as motocicletas têm 2 rodas. Não é necessariamente uma bicicleta."],
    "TLR811_2_12": ["Quatro amigos têm pontuações diferentes: 70, 80, 90, 100. James obteve mais de 80, mas menos de 100. Qual foi a pontuação dele?", "Qual pontuação está entre 80 e 100?", ["70", "80", "90", "100"], "A única pontuação entre 80 e 100 é 90."],
    "TLR811_2_13": ["Todas as aranhas têm 8 patas. Esta criatura tem 8 pernas. É uma aranha SEGURA?", "Só as aranhas têm 8 patas?", ["Sim", "Não, não necessariamente", "Somente os grandes", "Sempre"], "E os escorpiões têm 8 patas. 8 pernas não significa necessariamente uma aranha."],
    "TLR811_2_14": ["O carvalho é mais alto que a bétula. O pinheiro é mais alto que o carvalho. O olmo é mais curto que a bétula. Qual árvore é a mais alta?", "Organize todas as quatro árvores.", ["O carvalho", "A bétula", "O pinheiro", "O Olmo"], "Pinho > Carvalho > Bétula > Olmo. O pinheiro é o mais alto."],
    "TLR811_2_15": ["Todos os planetas orbitam em torno de uma estrela. Earth orbits a star. Isso prova que a Terra é um planeta?", "Apenas os planetas orbitam estrelas?", ["Sim, isso prova", "Não, isso não prova isso", "Só às vezes", "Sempre"], "E cometas, asteroides orbitam estrelas. A órbita por si só não prova que é um planeta."],
    "TLR811_2_16": ["Sam tem mais adesivos que Mia. Mia tem mais do que Jo. Jo tem mais do que Lee. Quem tem menos?", "Encomende-os.", ["Sam", "Mia", "Jô", "Lee"], "Sam > Mia > Jo > Lee. Lee tem o menor número."],
    "TLR811_2_17": ["Se chover, o chão fica molhado. O chão está molhado. Está chovendo com certeza?", "O solo poderia estar molhado por outros motivos?", ["Sim, claro", "Não, não necessariamente", "Só no verão", "Sempre"], "Alguém poderia ter lavado tudo. Solo molhado não prova chuva."],
    "TLR811_2_18": ["O gato pesa menos que o cachorro. O cachorro menos que a ovelha. A ovelha menos que a vaca. Qual animal pesa mais?", "Classifique por peso.", ["O gato", "O cachorro", "As ovelhas", "A vaca"], "Gato < Cachorro < Ovelha < Vaca. A vaca pesa mais."],
    "TLR811_2_19": ["Todas as maçãs são frutas. Isso NÃO é fruta. Pode ser maçã?", "Se todas as maçãs são frutas e esta não é fruta...", ["Sim", "Não, não pode", "Talvez", "Somente os verdes"], "Todas as maçãs são frutas. Se não for fruta, não pode ser maçã."],
    "TLR811_2_20": ["Quatro crianças têm 8, 9, 10, 11 anos. Kai é maior que Zoe. Zoe do que Leo. Leo do que Ivy. quantos anos tem Zoe", "Kai é o mais velho, depois Zoe, Leo, Ivy.", ["8", "9", "10", "11"], "Kai=11, Zoe=10, Leão=9, Ivy=8. Zoé tem 10 anos."],
    "TLR811_3_01": ["Se chover, Tom leva guarda-chuva. Se ele levar guarda-chuva, ele fica seco. Está chovendo. Tom ficará seco?", "A cadeia segue: chuva → guarda-chuva → seco.", ["Sim", "Não", "Talvez", "Só se estiver frio"], "Chuva → guarda-chuva → seco. Está chovendo, então Tom fica seco."],
    "TLR811_3_02": ["Se A é verdade, então B é verdade. B não é verdade. A é verdade?", "Se A implica B e B é falso…", ["Sim", "Não", "Talvez", "Não podemos saber"], "Se A fosse verdade, B teria de ser verdade. Mas B não é. Logo A não pode ser verdade."],
    "TLR811_3_03": ["Hoje é quarta-feira. Que dia foi há 3 dias?", "Contagem regressiva: terça, segunda, domingo.", ["Segunda-feira", "domingo", "Sábado", "Terça-feira"], "Quarta-feira −1 = terça-feira, −2 = segunda-feira, −3 = domingo."],
    "TLR811_3_04": ["Se você estudar, você passa no teste. Se você passar no teste, receberá a recompensa. Maya aprendeu. Maya recebe sua recompensa?", "The chain follows: learning → passing test → reward.", ["Sim", "Não", "Só às vezes", "Não podemos saber"], "Aprendizagem → aprovação → recompensa. Maya aprendeu, então ela recebe a recompensa."],
    "TLR811_3_05": ["Se Anna nada, ela usa óculos de natação. Anna NÃO usa óculos. Anna nada?", "Se ele sempre usa óculos quando nada, e agora não usa...", ["Sim", "Não", "Talvez", "Somente segunda-feira"], "Se ele estivesse nadando, ele usaria óculos de proteção. Não carrega, então não nada."],
    "TLR811_3_06": ["Hoje é 28 de março. Qual é a data daqui a 5 dias?", "Março tem 31 dias. Conte a partir de 28.", ["33 de março", "1º de abril", "2 de abril", "3 de abril"], "Março tem 31 dias. 28 + 5 = 33. 33 − 31 = 2. Então é 2 de abril."],
    "TLR811_3_07": ["Se Max comer bolo, ele ficará doente. Max NÃO está ferido. Max comeu bolo?", "Se o bolo sempre o deixa enjoado, e agora ele não...", ["Sim", "Não", "Talvez", "Só bolo de chocolate"], "Se ele comesse bolo, ficaria doente. Ele não está com vontade, então não comeu."],
    "TLR811_3_08": ["Se A leva a B, B a C, C a D. A acontece. D acontece?", "A cadeia de A a D segue.", ["Sim", "Não", "Só às vezes", "Não podemos saber"], "A → B → C → D. Se A, então D."],
    "TLR811_3_09": ["É outubro. Quantos meses até março (contando crescente)?", "Número: novembro, dezembro, janeiro, fevereiro, março.", ["4", "5", "6", "3"], "Novembro (1), dezembro (2), janeiro (3), fevereiro (4), março (5). São 5 meses."],
    "TLR811_3_10": ["Se uma forma tiver 4 lados iguais e 4 ângulos retos, ela é quadrada. Esta forma NÃO possui 4 lados iguais. Tem certeza que NÃO é quadrado?", "Pode ser um quadrado sem 4 lados iguais?", ["Sim, não é quadrado", "Não, ainda pode ser quadrado", "Talvez", "Só se for grande"], "O quadrado deve ter 4 lados iguais. Se não os tiver, não é quadrado."],
    "TLR811_3_11": ["Se você pressionar o botão, a luz acende. Se a luz acender, a campainha toca. Você apertou o botão. o que está acontecendo", "A cadeia segue: botão → luz → campainha.", ["Nada", "Apenas a luz", "A campainha toca", "O botão quebra"], "Botão → luz → campainha. Você pressionou, então a campainha toca."],
    "TLR811_3_12": ["Hoje é sexta-feira. Que dia será daqui a 10 dias?", "10 = 7 + 3. Uma semana inteira mais 3 dias.", ["domingo", "Segunda-feira", "Terça-feira", "Quarta-feira"], "10 dias = 1 semana + 3 dias. Sexta-feira + 3 = segunda-feira."],
    "TLR811_3_13": ["Todos os alunos da classe A jogam futebol. Tom NÃO joga futebol. Tom está na classe A?", "Se todos em A jogam futebol e Tom não…", ["Sim", "Não", "Talvez", "Somente nos finais de semana"], "Todos em A jogam futebol. Tom não joga, então ele não está na classe A."],
    "TLR811_3_14": ["Se nevar, a escola fecha. Se a escola estiver fechada, as crianças brincam ao ar livre. NÃO nevou. Podemos ter CERTEZA de que as crianças NÃO estão brincando lá fora?", "A escola poderia estar fechando por outro motivo?", ["Sim, temos certeza", "Não, não podemos ter certeza", "Só no verão", "Sempre"], "A escola também pode fechar por outros motivos (férias, reparos). As crianças ainda podiam brincar lá fora."],
    "TLR811_3_15": ["Hoje é 30 de novembro. Qual é a data daqui a 3 dias?", "Novembro tem 30 dias; o que vem depois de 30 de novembro?", ["33 de novembro", "1º de dezembro", "2 de dezembro", "3 de dezembro"], "Novembro tem 30 dias. 30 de novembro +1 = 1º de dezembro, +2 = 2 de dezembro, +3 = 3 de dezembro"],
    "TLR811_3_16": ["X é maior que Y. Y que Z. Z que W. W que V. Qual é maior?", "Quem está no topo da cadeia?", ["V", "o que", "S", "X"], "X > Y > Z > W > V. X é o maior."],
    "TLR811_3_17": ["Todos os peixes podem nadar. Algo não sabe nadar. é peixe", "Se todos os peixes nadarem e isso não…", ["Sim", "Não", "Talvez", "Apenas peixes pequenos"], "Todos os peixes nadam. Se não sabe nadar, não é um peixe."],
    "TLR811_3_18": ["Hoje é terça-feira. Que dia será daqui a 25 dias?", "25 ÷ 7 = 3 semanas e 4 dias extras.", ["Sexta-feira", "Sábado", "Domingo", "Segunda-feira"], "25 = 3 semanas + 4 dias. Terça + 4 = Sábado."],
    "TLR811_3_19": ["Se A for verdadeiro, B deve ser verdadeiro. Se B for verdadeiro, C deve ser verdadeiro. C NÃO é verdade. A é verdade?", "Funciona ao contrário: se C for falso, e B? Então com A?", ["Sim", "Não", "Talvez", "Não podemos saber"], "Se A → B → C. C é falso, então B é falso, então A é falso."],
    "TLR811_3_20": ["Todo gato é peludo. Qualquer coisa peluda é macia. Qualquer coisa macia é gostosa de abraçar. Bigodes é um gato. É bom abraçar bigodes?", "A cadeia segue: gato → peludo → macio → abraçável.", ["Sim", "Não", "Talvez", "Só os gatinhos"], "Gato → peludo → macio → legal. Bigodes é um gato, então é bom abraçar."],
    "TSR811_1_01": ["Quantas faces um cubo tem?", "Pense em um dado – conte as faces planas.", ["4", "6", "8", "12"], "Um cubo tem 6 faces planas."],
    "TSR811_1_02": ["Quantas arestas um cubo tem?", "Uma aresta é onde duas faces se encontram. Conte todas as arestas.", ["6", "8", "10", "12"], "Um cubo tem 12 arestas."],
    "TSR811_1_03": ["Quantos vértices (cantos) um cubo tem?", "Um vértice é o ponto onde as arestas se encontram.", ["4", "6", "8", "12"], "Um cubo possui 8 vértices (cantos)."],
    "TSR811_1_04": ["Qual é a forma de cada face de um cubo?", "Todas as faces do cubo têm a mesma forma.", ["Triângulo", "Retângulo", "Quadrado", "Círculo"], "Cada face de um cubo é um quadrado."],
    "TSR811_1_05": ["Quantas faces tem uma caixa retangular (cuboide)?", "Pense em uma caixa de sapatos. Conte faces planas.", ["4", "5", "6", "8"], "Um cubóide (caixa retangular) possui 6 faces."],
    "TSR811_1_06": ["Quantas faces planas tem uma esfera?", "Uma esfera é como uma bola.", ["0", "1", "2", "4"], "Uma esfera tem 0 faces planas. É totalmente arredondado."],
    "TSR811_1_07": ["Quantas faces planas tem um cilindro?", "Pense em uma lata. Quais lados planos ele tem?", ["0", "1", "2", "3"], "Um cilindro possui 2 faces planas (círculo superior e círculo inferior)."],
    "TSR811_1_08": ["Qual forma 3D tem 6 faces quadradas, todas iguais?", "Todas as faces são quadrados idênticos.", ["Cubóide", "Cubos", "Prisma", "Pirâmide"], "Um cubo tem 6 faces quadradas idênticas."],
    "TSR811_1_09": ["Quantas faces planas tem um cone?", "Pense em uma casquinha de sorvete. Possui uma única base plana.", ["0", "1", "2", "3"], "Um cone possui 1 face plana (base circular)."],
    "TSR811_1_10": ["Quantas arestas tem uma pirâmide triangular (tetraedro)?", "Possui 4 faces triangulares. Conte onde os triângulos se encontram.", ["4", "5", "6", "8"], "Uma pirâmide triangular (tetraedro) tem 6 arestas."],
    "TSR811_1_11": ["Se você olhar para um cubo diretamente de frente, que forma você vê?", "Veja uma face do cubo frontal.", ["Triângulo", "Círculo", "Quadrado", "Retângulo"], "Olhando diretamente para uma face de um cubo, você vê um quadrado."],
    "TSR811_1_12": ["Quantas faces tem um prisma triangular?", "Pense em uma caixa de Toblerone – 2 triângulos e alguns retângulos.", ["3", "4", "5", "6"], "Um prisma triangular possui 5 faces: 2 triângulos e 3 retângulos."],
    "TSR811_1_13": ["Quantos vértices tem uma pirâmide triangular (tetraedro)?", "Conte os cantos afiados.", ["3", "4", "5", "6"], "Uma pirâmide triangular tem 4 vértices."],
    "TSR811_1_14": ["Qual é o formato da base de um cone?", "A base plana de um cone é…", ["Quadrado", "Triângulo", "Círculo", "Oval"], "A base de um cone é um círculo."],
    "TSR811_1_15": ["Quantas arestas um cubóide tem?", "Um cubóide é como um cubo, mas com faces retangulares. Conte as bordas.", ["8", "10", "12", "14"], "Um cubóide tem 12 arestas, assim como um cubo."],
    "TSR811_1_16": ["Quantas faces tem uma pirâmide de base quadrada?", "Possui base quadrada e faces laterais triangulares.", ["4", "5", "6", "8"], "Uma pirâmide de base quadrada tem 5 faces: 1 base quadrada e 4 triângulos."],
    "TSR811_1_17": ["Se você empilhar 2 cubos um em cima do outro, a forma combinada mais se assemelhará a…", "Dois cubos empilhados formam uma forma mais alta.", ["Cubos", "Esferas", "Cubóide", "Cilindro"], "Dois cubos empilhados formam um cubóide (caixa retangular)."],
    "TSR811_1_18": ["Quantos vértices um cubóide tem?", "Conte todos os cantos de uma caixa retangular.", ["4", "6", "8", "10"], "Um cubóide tem 8 vértices, assim como um cubo."],
    "TSR811_1_19": ["Quantas superfícies curvas uma esfera tem?", "Uma esfera é perfeitamente redonda.", ["0", "1", "2", "4"], "Uma esfera tem 1 superfície curva."],
    "TSR811_1_20": ["Quantas faces tem um prisma hexagonal?", "Possui 2 extremidades hexagonais e faces laterais retangulares. O hexágono tem 6 lados.", ["6", "7", "8", "10"], "Um prisma hexagonal possui 8 faces: 2 hexágonos + 6 retângulos."],
    "TSR811_2_01": ["Se você cortar um cubo exatamente ao meio, paralelo a uma das faces, qual será o formato da seção?", "Corte reto, como cortar pão.", ["Triângulo", "Círculo", "Quadrado", "Retângulo"], "Cortar o cubo paralelamente a uma face resulta em uma seção quadrada."],
    "TSR811_2_02": ["8 cubos pequenos formam um cubo 2×2×2. Quantos cubos pequenos estão completamente ocultos (sem faces visíveis)?", "No arranjo 2×2×2, cada cubo fica do lado de fora.", ["0", "1", "2", "4"], "No cubo 2×2×2, cada cubo pequeno está no canto com faces visíveis. Nenhum está oculto."],
    "TSR811_2_03": ["Quantas arestas tem um prisma triangular?", "3 arestas no triângulo superior + 3 na parte inferior + 3 conectando-as.", ["6", "8", "9", "12"], "Um prisma triangular tem 9 arestas: 3 + 3 + 3."],
    "TSR811_2_04": ["Você alinha 3 cubos um após o outro, frente a frente. Quantas faces dos cubos pequenos estão ocultas (tocando outro cubo)?", "Onde os cubos se tocam, 2 faces ficam escondidas em cada junta.", ["2", "3", "4", "6"], "Existem 2 articulações. Cada um esconde 2 faces. Total de faces ocultas: 2 × 2 = 4."],
    "TSR811_2_05": ["Quantas arestas tem uma pirâmide de base quadrada?", "4 arestas na base + 4 na parte superior.", ["5", "6", "8", "10"], "Uma pirâmide de base quadrada tem 8 arestas: 4 na base + 4 nas laterais."],
    "TSR811_2_06": ["Se você cortar um cilindro ao meio (perpendicular à altura), qual será o formato da seção?", "Corte como um tronco, perpendicular ao eixo.", ["Quadrado", "Retângulo", "Círculo", "Oval"], "Cortando o cilindro perpendicularmente à altura você obtém um círculo."],
    "TSR811_2_07": ["27 cubos pequenos formam um cubo 3×3×3. Quantos cubos pequenos têm pelo menos uma face visível do lado de fora?", "Apenas o cubo exatamente no centro fica completamente oculto.", ["24", "25", "26", "27"], "Apenas 1 cubo (o do centro) está oculto. 27 − 1 = 26 cubos têm pelo menos uma face visível."],
    "TSR811_2_08": ["Quantas faces tem um prisma pentagonal?", "2 cabeças pentagonais + faces retangulares. O pentágono tem 5 lados.", ["5", "6", "7", "8"], "Um prisma pentagonal tem 7 faces: 2 pentágonos + 5 retângulos."],
    "TSR811_2_09": ["Quantos vértices tem uma pirâmide de base quadrada?", "4 cantos na base + 1 ponta no topo.", ["4", "5", "6", "8"], "Uma pirâmide de base quadrada possui 5 vértices: 4 na base + 1 vértice."],
    "TSR811_2_10": ["4 cubos são colocados em um quadrado 2×2, camada única. Quantos rostos podem ser vistos de cima?", "Cada cubo mostra 1 face para cima.", ["2", "3", "4", "8"], "Cada um dos 4 cubos mostra 1 face para cima. Total = 4 faces para cima."],
    "TSR811_2_11": ["Quantas faces tem uma pirâmide hexagonal?", "1 base hexagonal + faces laterais triangulares. O hexágono tem 6 lados.", ["6", "7", "8", "9"], "Uma pirâmide hexagonal tem 7 faces: 1 hexágono + 6 triângulos."],
    "TSR811_2_12": ["Se você cortar um cubo de uma borda à outra (na diagonal através do meio), a seção será uma…", "O corte é diagonal, mas permanece plano.", ["Triângulo", "Quadrado", "Retângulo", "Círculo"], "Cortar de uma borda à outra resulta em uma seção retangular."],
    "TSR811_2_13": ["Quantas faces tem uma pirâmide triangular (tetraedro)?", "Todas as suas faces são triângulos.", ["3", "4", "5", "6"], "Uma pirâmide triangular tem 4 faces triangulares."],
    "TSR811_2_14": ["8 cubos formam um cubo 2×2×2. Quantas faces dos cubos pequenos são visíveis do lado de fora do cubo grande?", "O cubo grande tem 6 faces, cada uma composta por 4 faces pequenas.", ["16", "20", "24", "32"], "6 faces grandes × 4 faces pequenas cada = 24 faces pequenas visíveis."],
    "TSR811_2_15": ["Quantos vértices tem uma pirâmide de base pentagonal?", "5 cantos na base + 1 ponta no topo.", ["5", "6", "7", "10"], "Uma pirâmide pentagonal possui 6 vértices: 5 na base + 1 vértice."],
    "TSR811_2_16": ["Quantas arestas tem um prisma hexagonal?", "6 para cima + 6 para baixo + 6 conectando-os.", ["12", "14", "16", "18"], "Um prisma hexagonal tem 18 arestas: 6 + 6 + 6."],
    "TSR811_2_17": ["Remova um cubo de canto de um arranjo 2×2×2. Quantos cubos pequenos sobraram?", "Você tem 8 cubos pequenos e remove 1.", ["5", "6", "7", "4"], "8 − 1 = restam 7 cubos."],
    "TSR811_2_18": ["Quantos vértices tem um prisma triangular?", "3 cantos em cada extremidade triangular.", ["4", "5", "6", "8"], "Um prisma triangular possui 6 vértices: 3 em cada triângulo."],
    "TSR811_2_19": ["Se você pintar todas as faces de um cubo 2×2×2 e desdobrá-lo, quantos cubos pequenos têm exatamente 3 faces pintadas?", "No cubo 2×2×2, cada cubo pequeno está no canto.", ["4", "6", "8", "0"], "Todos os 8 cubos em 2×2×2 são de canto, então todos os 8 têm exatamente 3 faces pintadas."],
    "TSR811_2_20": ["Quantas faces tem um prisma octogonal?", "2 extremidades octogonais + faces retangulares. O octógono tem 8 lados.", ["8", "10", "12", "16"], "Um prisma octogonal possui 10 faces: 2 octógonos + 8 retângulos."],
    "TSR811_3_01": ["Quantos quadrados um cubo desdobra (a versão desdobrada)?", "Cada face do cubo torna-se um quadrado desdobrado.", ["4", "5", "6", "8"], "Um cubo tem 6 faces, então desdobrado tem 6 quadrados."],
    "TSR811_3_02": ["Em um cubo 3×3×3 com 27 cubos pequenos, quantos cubos estão completamente escondidos (nenhuma face visível)?", "Somente o cubo exatamente no centro não está voltado para fora.", ["0", "1", "4", "8"], "Apenas 1 cubo, aquele que está exatamente no centro, está completamente oculto."],
    "TSR811_3_03": ["Quando você dobra uma cruz desdobrada (como mais 6 quadrados), que forma 3D você obtém?", "Desdobrado em cruz é um dos mais comuns para um formato muito conhecido.", ["Pirâmide", "Cubóide", "Cubos", "Prisma"], "Um cruzamento de 6 quadrados se transforma em um cubo."],
    "TSR811_3_04": ["Em um cubo 3×3×3, quantos cubos pequenos têm exatamente 3 faces visíveis?", "Os cubos de canto têm 3 faces visíveis. Quantos cantos um cubo tem?", ["4", "6", "8", "12"], "Um cubo tem 8 cantos. Cada cubo de canto possui exatamente 3 faces visíveis."],
    "TSR811_3_05": ["Se você colar 2 cubos em uma face, quantas faces a nova forma terá no total?", "Cada cubo tem 6 faces, mas 2 ficam escondidas onde estão coladas.", ["8", "10", "11", "12"], "6 + 6 = 12 faces no total. Subtraia 2 faces ocultas: 12 − 2 = 10."],
    "TSR811_3_06": ["Em um cubo 3×3×3, quantos cubos pequenos têm exatamente 2 faces visíveis?", "Os cubos nas bordas (não nos cantos) têm 2 faces visíveis. Quantas arestas um cubo tem?", ["6", "8", "12", "24"], "Um cubo tem 12 arestas. Em cada aresta há 1 cubo que não é um canto. 12 × 1 = 12 cubos de 2 lados."],
    "TSR811_3_07": ["Se você cortar um cubo com um único corte reto, quantas peças você conseguirá no máximo?", "Um único corte divide-se em no máximo 2 partes.", ["2", "3", "4", "6"], "Um corte reto em qualquer formato rende no máximo 2 peças."],
    "TSR811_3_08": ["Em um cubo 3×3×3, quantos cubos pequenos têm exatamente 1 face visível?", "Os cubos no centro de cada face possuem 1 face visível. Um cubo tem 6 faces.", ["4", "6", "8", "12"], "Em cada uma das 6 faces existe 1 cubo central. 6 × 1 = 6 cubos com exatamente 1 face."],
    "TSR811_3_09": ["Em quantas formas consiste um desdobramento de uma pirâmide de base quadrada?", "Conte a base triangular e as faces.", ["4", "5", "6", "8"], "Desdobra-se em 5 formas: 1 quadrado (base) + 4 triângulos (lados)."],
    "TSR811_3_10": ["Se você colar 3 cubos seguidos (face a face), quantas faces terá a nova forma?", "3 cubos = 18 faces no total. Existem 2 juntas, cada uma escondendo 2 faces.", ["12", "14", "16", "18"], "3 × 6 = 18 faces. 2 junções × 2 faces ocultas = 4 ocultas. 18 − 4 = 14."],
    "TSR811_3_11": ["Em um cubo 4×4×4 (64 cubos pequenos), quantos cubos pequenos existem na superfície?", "Total de cubos menos os que estão dentro. O interior é 2×2×2.", ["48", "52", "56", "60"], "Interior = 2×2×2 = 8 cubos. Fora = 64 − 8 = 56."],
    "TSR811_3_12": ["Se você pintar um cubo 3×3×3 e quebrá-lo em cubos pequenos, quantos não terão tinta alguma?", "Somente o cubo exatamente no centro não tem face pintada.", ["0", "1", "4", "8"], "Apenas o cubo do centro não toca o exterior, por isso não tem tinta."],
    "TSR811_3_13": ["Uma rede para um prisma triangular tem quantas formas?", "2 extremidades triangulares + lados retangulares.", ["3", "4", "5", "6"], "A rede tem 5 formas: 2 triângulos + 3 retângulos."],
    "TSR811_3_14": ["Se você pintar um cubo 2×2×2 e dividi-lo em 8 cubos pequenos, exatamente quantas 3 faces serão pintadas?", "Em 2×2×2, cada cubo está no canto.", ["4", "6", "8", "2"], "Todos os 8 estão no canto, então todos têm exatamente 3 faces pintadas."],
    "TSR811_3_15": ["Olhando para um cubo de um canto, quantas faces você consegue ver ao mesmo tempo?", "De um canto você vê os rostos se encontrando ali.", ["1", "2", "3", "4"], "De um canto do cubo você vê no máximo 3 faces."],
    "TSR811_3_16": ["Em um cubo 3×3×3, o número total de pequenas faces visíveis do lado de fora é…?", "O cubo grande tem 6 faces, cada uma com 9 faces pequenas.", ["36", "48", "54", "27"], "6 faces grandes × 9 faces pequenas = 54 faces pequenas visíveis."],
    "TSR811_3_17": ["Se você colar 2 cubos lado a lado e colocar o terceiro em cima de um (formato L), quantas faces a forma tem?", "2 cubos colados = 10 faces. O terceiro acima esconde mais 2 faces.", ["12", "14", "16", "18"], "2 cubos colados = 10 faces. Terceiro cubo: 10 + 6 − 2 = 14 faces."],
    "TSR811_3_18": ["Quantos cubos pequenos são necessários para construir um cubo 4×4×4?", "Multiplique 4 × 4 × 4.", ["16", "32", "48", "64"], "4 × 4 × 4 = 64 cubos pequenos."],
    "TSR811_3_19": ["Em um cubo 3×3×3, quantos cubos pequenos compartilham uma face com o cubo central?", "O cubo central é tocado pelos cubos superior, inferior, esquerdo, direito, frontal e traseiro.", ["4", "6", "8", "12"], "O cubo central pode ser alcançado em 6 direções: cima, baixo, esquerda, direita, frente, trás."],
    "TSR811_3_20": ["Se você colar 6 cubos em um retângulo plano 2×3×1, quantas faces a forma terá?", "6 cubos = 36 faces. Conta junções internas que ocultam faces.", ["18", "20", "22", "24"], "6 × 6 = 36 faces. Existem 7 juntas internas (4 horizontais + 3 verticais), cada uma escondendo 2 faces: 36 − 14 = 22."],
    "TMP811_1_01": ["Um fazendeiro tem 25 ovelhas. Todos fogem, exceto 9. Quantas ovelhas sobraram?", "\"Todos menos 9\" significa que 9 não foi executado.", ["16", "9", "25", "0"], "\"Todos menos 9 correm\" significa que 9 ficam. A resposta é 9."],
    "TMP811_1_02": ["3 amigos compartilham 12 biscoitos igualmente. How much does each get?", "Divida 12 por 3.", ["3", "4", "5", "6"], "12 ÷ 3 = 4 biscoitos cada."],
    "TMP811_1_03": ["Uma loja vende maçãs por £ 2 cada. Quanto custam 5 maçãs?", "Multiplique o preço unitário pelo número de maçãs.", ["£ 7", "£ 8", "£ 10", "£ 12"], "5 × £ 2 = £ 10."],
    "TMP811_1_04": ["Quantos meses do ano têm 28 dias?", "Pense nisso: apenas alguns meses têm 28 dias?", ["1", "6", "12", "2"], "Todos os 12 meses têm pelo menos 28 dias!"],
    "TMP811_1_05": ["Um livro tem 6 capítulos, cada um com 10 páginas. Quantas páginas tem no total?", "Multiplique o número de capítulos pelas páginas por capítulo.", ["16", "50", "60", "66"], "6 × 10 = 60 páginas."],
    "TMP811_1_06": ["Você tem 3 caixas, cada uma com 4 bolas. Quantas bolas você tem no total?", "Multiplique as caixas pelas bolas de cada caixa.", ["7", "9", "12", "15"], "3 × 4 = 12 bolas."],
    "TMP811_1_07": ["In a race, you overtake the 2nd place finisher. Onde você está agora?", "Se você ultrapassar o que está em 2º lugar, você ocupa o lugar dele.", ["1º lugar", "2º lugar", "3º lugar", "4º lugar"], "Você está em 2º lugar. Você passou no segundo, não no primeiro."],
    "TMP811_1_08": ["Um padeiro faz 5 bolos por hora. Quantas torturas ele faz em 4 horas?", "Multiplique as torturas por hora pelo número de horas.", ["9", "15", "20", "25"], "5 × 4 = 20 bolos."],
    "TMP811_1_09": ["Tom tem 8 brinquedos. Ele ganha mais 3 em seu aniversário. Quanto ele tem agora?", "Adicione novos brinquedos aos que ele já tinha.", ["5", "10", "11", "12"], "8 + 3 = 11 brinquedos."],
    "TMP811_1_10": ["O que pesa mais: 1kg de penas ou 1kg de pedras?", "Olha o peso – ambos pesam 1kg.", ["Penas", "As pedras", "Da mesma forma", "Depende"], "Ambos pesam 1 kg, então a mesma coisa!"],
    "TMP811_1_11": ["Uma aranha tem 8 patas. Quantas pernas têm 3 aranhas?", "Multiplique as pernas de uma aranha pelo número de aranhas.", ["16", "20", "24", "28"], "3 × 8 = 24 pés."],
    "TMP811_1_12": ["Você tem 20 doces e come 3 por dia. Depois de 4 dias, quantos sobraram?", "Primeiro calcule quanto você comeu no total.", ["5", "8", "10", "12"], "4 × 3 = 12 comidos. 20 - 12 = 8 restantes."],
    "TMP811_1_13": ["Quantos lados tem um círculo?", "Um lado é uma aresta reta. O círculo tem arestas retas?", ["0", "1", "2", "4"], "Um círculo tem 0 lados retos."],
    "TMP811_1_14": ["Um carro tem 4 rodas. Quantas rodas têm 5 carros?", "Multiplique as rodas de um carro pelo número de carros.", ["9", "15", "16", "20"], "5 × 4 = 20 rodas."],
    "TMP811_1_15": ["O duzină de ouă înseamnă 12. Câte ouă sunt jumătate de duzină?", "Metade de 12 é…", ["4", "5", "6", "8"], "Meia dúzia = 12 ÷ 2 = 6."],
    "TMP811_1_16": ["Se hoje é seu aniversário de 9 anos, quantos aniversários você já fez até agora?", "O primeiro aniversário foi quando você completou 1 ano; agora é dia 9.", ["8", "9", "10", "1"], "9º aniversário significa que você comemorou 9 vezes."],
    "TMP811_1_17": ["Uma semana tem 7 dias. Quantos dias existem em 3 semanas?", "Multiplique os dias da semana pelo número de semanas.", ["10", "14", "21", "28"], "3 × 7 = 21 dias."],
    "TMP811_1_18": ["Você tem £ 5,00 e gasta £ 1,50. Quanto você ainda tem?", "Subtraia o que você gastou.", ["£ 2,50", "£ 3,00", "£ 3,50", "£4,00"], "£ 5,00 - £ 1,50 = £ 3,50."],
    "TMP811_1_19": ["4 amigos têm 6 bolas cada. Quantas bolas eles têm juntos?", "Multiplique o número de amigos pelas bolas de cada pessoa.", ["10", "18", "20", "24"], "4 × 6 = 24 bolas."],
    "TMP811_1_20": ["Quantos minutos existem em meia hora?", "Uma hora tem 60 minutos.", ["20", "25", "30", "45"], "Metade de 60 minutos = 30 minutos."],
    "TMP811_2_01": ["Um caracol percorre 3 cm em um minuto. Quão longe ele vai em 10 minutos?", "Multiplique a velocidade pelo tempo.", ["13 cm", "30 centímetros", "33 centímetros", "300 centímetros"], "3 × 10 = 30 cm."],
    "TMP811_2_02": ["Em um quadrado mágico, cada linha soma 15. A primeira linha é: 2, ?, 6. Qual é o número que falta?", "2+? + 6 = 15.", ["5", "6", "7", "8"], "2+? + 6 = 15, então? = 15 − 2 − 6 = 7."],
    "TMP811_2_03": ["24 doces são divididos igualmente entre 6 crianças. Câte primește fiecare?", "Divida os doces de acordo com o número de crianças.", ["3", "4", "5", "6"], "24 ÷ 6 = 4 doces cada."],
    "TMP811_2_04": ["Uma torneira enche um balde em 10 minutos. Quantos baldes ele consegue encher em uma hora?", "1 hora = 60 minutos.", ["4", "5", "6", "10"], "60 ÷ 10 = 6 baldes."],
    "TMP811_2_05": ["Num quadrado mágico (soma 15), uma linha é: 6, 5, ?. Qual é o número que falta?", "6+5+? = 15.", ["3", "4", "5", "6"], "6+5+? = 15, então? = 15 − 6 − 5 = 4."],
    "TMP811_2_06": ["Uma bicicleta percorre 12 km por hora. Qual a distância que ele percorre em 3 horas?", "Multiplique a velocidade pelo tempo.", ["15km", "24 km", "36 km", "48 km"], "12 × 3 = 36 km."],
    "TMP811_2_07": ["3 amigos encontram £ 30 e dividem igualmente. Quanto cada um ganha?", "Divida £ 30 por 3.", ["£ 5", "£ 10", "£ 12", "£ 15"], "£ 30 ÷ 3 = £ 10 cada."],
    "TMP811_2_08": ["Uma fábrica produz 50 brinquedos por dia. How much does he make in 5 days?", "Multiplique os brinquedos por dia pelo número de dias.", ["55", "100", "200", "250"], "50 × 5 = 250 brinquedos."],
    "TMP811_2_09": ["Num quadrado mágico (soma 15), uma linha é: 8, 3, ?. Qual é o número que falta?", "8+3+? = 15.", ["3", "4", "5", "6"], "8+3+? = 15, então? = 15 − 8 − 3 = 4."],
    "TMP811_2_10": ["Você compra 3 produtos por £ 4,50 cada. Quanto você paga no total?", "Multiplique o preço pela quantidade.", ["£ 12,00", "£ 13,50", "£ 14,50", "£ 15,00"], "3 × £ 4,50 = £ 13,50."],
    "TMP811_2_11": ["Um trem viaja a 60 km por hora. Qual a distância que ele percorre em 2 horas?", "Multiplique a velocidade pelo tempo.", ["62 km", "90 km", "100 km", "120 km"], "60 × 2 = 120 quilômetros."],
    "TMP811_2_12": ["36 maçãs são colocadas em caixas de 9. Quantas caixas são necessárias?", "Divida 36 por 9.", ["3", "4", "5", "6"], "36 ÷ 9 = 4 caixas."],
    "TMP811_2_13": ["Num quadrado mágico (soma 15), uma linha é: 8, 1, ?. Qual é o número que falta?", "8 + 1 + ? = 15.", ["4", "5", "6", "7"], "8 + 1 + ? = 15, so ? = 15 − 8 − 1 = 6."],
    "TMP811_2_14": ["Você tem £ 20. Um livro custa £3,50. Quantos livros você pode comprar?", "Deixe cair £ 3,50 repetidamente até não conseguir mais.", ["4", "5", "6", "7"], "5 × £ 3,50 = £ 17,50 (suficiente). 6 × £ 3,50 = £ 21,00 (muito). Você pode comprar 5."],
    "TMP811_2_15": ["Uma mangueira de jardim enche 2 litros por minuto. Quantos litros em 15 minutos?", "Multiplique o fluxo pelo tempo.", ["17", "25", "30", "32"], "2 × 15 = 30 litros."],
    "TMP811_2_16": ["5 crianças compartilham igualmente 35 adesivos. Quanto cada um ganha?", "Divida 35 por 5.", ["5", "6", "7", "8"], "35 ÷ 5 = 7 adesivos cada."],
    "TMP811_2_17": ["Num quadrado mágico (soma 15), uma linha é: 4, 9, ?. Qual é o número que falta?", "4+9+? = 15.", ["1", "2", "3", "4"], "4+9+? = 15, então? = 15 − 4 − 9 = 2."],
    "TMP811_2_18": ["Economize £ 5 por semana. Em quantas semanas você arrecada £ 40?", "Divida £ 40 por £ 5.", ["6", "7", "8", "9"], "£ 40 ÷ £ 5 = 8 semanas."],
    "TMP811_2_19": ["Uma impressora imprime 10 páginas por minuto. Quanto tempo leva para imprimir 80 páginas?", "Ele divide as páginas em páginas por minuto.", ["6 minutos", "7 minutos", "8 minutos", "10 minutos"], "80 ÷ 10 = 8 minutos."],
    "TMP811_2_20": ["48 alunos são divididos em equipes de 8. Quantas equipes são formadas?", "Divida 48 por 8.", ["4", "5", "6", "7"], "48 ÷ 8 = 6 equipes."],
    "TMP811_3_01": ["Uma loja vende lápis por 50 centavos e canetas por £ 1,20. Você compra 3 lápis e 2 canetas. Quanto você paga?", "Calcule cada parte separadamente e depois some-as.", ["£ 3,50", "£ 3,90", "£ 4,10", "£ 4,50"], "3 × 50 centavos = £ 1,50. 2 × £ 1,20 = £ 2,40. Total: £ 1,50 + £ 2,40 = £ 3,90."],
    "TMP811_3_02": ["Uma aranha tem 8 patas, um cachorro tem 4. Há 3 aranhas e 2 cachorros em uma sala. Quantos pés existem no total?", "Calcule primeiro as pernas das aranhas e depois dos cães.", ["28", "30", "32", "36"], "3 × 8 = 24 patas (aranhas). 2 × 4 = 8 pés (cães). 24 + 8 = 32."],
    "TMP811_3_03": ["O relógio marca 15h45. Que horas serão daqui a 2 horas e 30 minutos?", "Adicione primeiro as horas e depois os minutos.", ["17:15", "17:45", "18:15", "18:45"], "15h45 + 2 horas = 17h45. 17h45 + 30min = 18h15."],
    "TMP811_3_04": ["Você tem 3 moedas: 50p, 20p e 10p. Quantos valores diferentes você pode formar usando uma ou mais moedas?", "Liste todas as combinações: um, dois, todos os três.", ["5", "6", "7", "8"], "Simples: 50, 20, 10. Pares: 70, 60, 30. Todos os três: 80. Total de 7 valores."],
    "TMP811_3_05": ["Uma receita pede 250g de farinha para 4 pessoas. Quanta farinha você precisa para 12 pessoas?", "12 é 3 vezes mais que 4.", ["500g", "625g", "750g", "1000g"], "12 ÷ 4 = 3 vezes mais. 250 × 3 = 750g."],
    "TMP811_3_06": ["Um trem sai às 9h15 e chega às 11h45. Quanto tempo dura a viagem?", "Conte as horas e os minutos.", ["2 horas", "2 horas e 15 minutos", "2 horas e 30 minutos", "3 horas"], "Das 9h15 às 11h15 = 2 horas. Das 11h15 às 11h45 = 30 minutos. Total: 2 horas e 30 minutos."],
    "TMP811_3_07": ["Você compra produtos que custam £ 2,50, £ 3,75, £ 1,25 e £ 4,50. Quanto dinheiro você ganha com £ 20?", "Some todos os preços e subtraia £ 20.", ["£ 6,00", "£7,00", "£ 8,00", "£ 9,00"], "£ 2,50 + £ 3,75 + £ 1,25 + £ 4,50 = £ 12,00. Restante: £ 20 - £ 12 = £ 8,00."],
    "TMP811_3_08": ["Em uma sala há cadeiras (4 pés cada) e bancos (3 pés cada). Existem 5 cadeiras e alguns bancos. No total são 29 pés. Quantos bancos existem?", "Calcule primeiro as pernas da cadeira e depois encontre os bancos.", ["2", "3", "4", "5"], "5 cadeiras × 4 = 20 pés. 29 - 20 = 9 pés restantes. 9 ÷ 3 = 3 bancos."],
    "TMP811_3_09": ["Demora 5 minutos para cortar um tronco em 2 pedaços. Quanto tempo leva para cortá-lo em 4 pedaços?", "Para 4 peças você precisa de 3 cortes, não de 4.", ["10 minutos", "15 minutos", "20 minutos", "25 minutos"], "4 peças = 3 cortes. 3 × 5 = 15 minutos."],
    "TMP811_3_10": ["Um ônibus transporta 45 passageiros. São necessários 3 ônibus para uma viagem escolar. Qual é o número máximo de alunos que podem ir?", "Multiplique os assentos do ônibus pelo número de ônibus.", ["90", "120", "135", "150"], "3 × 45 = 135 alunos no máximo."],
    "TMP811_3_11": ["Você começa com £ 100. Você gasta um quarto, depois um terço do que sobra. Quanto você ainda tem?", "Um quarto de 100 = 25. Depois um terço de 75.", ["£ 40", "£ 45", "£50", "£ 55"], "Um quarto de £ 100 = £ 25 gastos, £ 75 restantes. Um terço de £ 75 = £ 25 gastos. £ 75 - £ 25 = £ 50."],
    "TMP811_3_12": ["A sessão começa às 14h50 e dura 1 hora e 25 minutos. A que horas termina?", "Adicione 1 hora e depois 25 minutos.", ["15:55", "16h05", "16h15", "16h25"], "14h50 + 1 hora = 15h50. 15h50 + 25min = 16h15."],
    "TMP811_3_13": ["Há duas vezes mais meninas do que meninos em uma classe. São 12 meninos. Quantas crianças existem no total?", "Meninas = 2 × meninos.", ["24", "30", "36", "48"], "Meninas = 2 × 12 = 24. Total = 12 + 24 = 36 crianças."],
    "TMP811_3_14": ["Você deseja cercar um jardim quadrado com 8m de lado. A cerca custa £ 5 por metro. Qual é o custo total?", "Primeiro encontre o perímetro e depois multiplique pelo preço do metro.", ["£ 120", "£ 140", "£ 160", "£ 200"], "Perímetro = 4 × 8 = 32 m. Custo = 32 × £ 5 = £ 160."],
    "TMP811_3_15": ["O filme começa às 19h40 e dura 1 hora e 50 minutos. A que horas termina?", "Adicione 1 hora (você obtém 20:40) e depois 50 minutos.", ["21:10", "21:20", "21h30", "21:40"], "19h40 + 1 hora = 20h40. 20h40 + 50min = 21h30."],
    "TMP811_3_16": ["Há vacas e galinhas no quintal. Números 8 cabeças e 26 pés. quantas vacas existem", "A vaca tem 4 patas, a galinha tem 2. Você pode verificar tentando.", ["3", "4", "5", "6"], "8 cabeças. Se fossem todas galinhas: 8 × 2 = 16 pés. Além disso: 26 − 16 = 10. Cada vaca adiciona 2 pernas extras: 10 ÷ 2 = 5 vacas."],
    "TMP811_3_17": ["Usando moedas de 5 centavos, 10 centavos e 20 centavos, de quantas maneiras diferentes você pode ganhar exatamente 25 centavos?", "Lista todas as combinações que somam 25p.", ["2", "3", "4", "5"], "Quatro modos: (1) 20+5, (2) 10+10+5, (3) 10+5+5+5, (4) 5+5+5+5+5."],
    "TMP811_3_18": ["Uma pista de corrida tem 400 m de comprimento. Um atleta corre 3 voltas. Quantos quilômetros ele percorre?", "1 km = 1000 m.", ["0,8km", "1,0 km", "1,2 km", "1,5km"], "3 × 400 = 1200 m = 1,2 km."],
    "TMP811_3_19": ["Uma caixa contém 24 doces. Você precisa disso para 100 pessoas (uma para cada). Quantas caixas você precisa comprar?", "4 caixas = 96 (não é suficiente). Experimente 5 caixas.", ["4", "5", "6", "10"], "4 caixas = 96 (não é suficiente). 5 caixas = 120 (suficiente). Você deve comprar 5."],
    "TMP811_3_20": ["Dois números têm uma soma de 50. Um é 14 maior que o outro. Qual é o número maior?", "Marque o número menor com um x. Então x + (x + 14) = 50.", ["28", "30", "32", "36"], "x + (x + 14) = 50. 2x = 36. x = 18. Maior = 18 + 14 = 32."],
  }
});
